/// PLIC Interrupt Source Peripheral.
///
/// Enumeration used to determine which peripheral asserted the corresponding
/// interrupt.
#[derive(Copy, Clone, PartialEq, Eq)]
#[repr(u32)]
pub enum PlicPeripheral {
    /// Unknown Peripheral
    Unknown = 0,
    /// uart0
    Uart0 = 1,
    /// uart1
    Uart1 = 2,
    /// uart2
    Uart2 = 3,
    /// uart3
    Uart3 = 4,
    /// gpio
    Gpio = 5,
    /// spi_device
    SpiDevice = 6,
    /// i2c0
    I2c0 = 7,
    /// i2c1
    I2c1 = 8,
    /// i2c2
    I2c2 = 9,
    /// pattgen
    Pattgen = 10,
    /// rv_timer
    RvTimer = 11,
    /// otp_ctrl
    OtpCtrl = 12,
    /// alert_handler
    AlertHandler = 13,
    /// spi_host0
    SpiHost0 = 14,
    /// spi_host1
    SpiHost1 = 15,
    /// usbdev
    Usbdev = 16,
    /// pwrmgr_aon
    PwrmgrAon = 17,
    /// sysrst_ctrl_aon
    SysrstCtrlAon = 18,
    /// adc_ctrl_aon
    AdcCtrlAon = 19,
    /// aon_timer_aon
    AonTimerAon = 20,
    /// sensor_ctrl_aon
    SensorCtrlAon = 21,
    /// flash_ctrl
    FlashCtrl = 22,
    /// hmac
    Hmac = 23,
    /// kmac
    Kmac = 24,
    /// otbn
    Otbn = 25,
    /// keymgr
    Keymgr = 26,
    /// csrng
    Csrng = 27,
    /// entropy_src
    EntropySrc = 28,
    /// edn0
    Edn0 = 29,
    /// edn1
    Edn1 = 30,
}

impl TryFrom<u32> for PlicPeripheral {
    type Error = u32;
    fn try_from(val: u32) -> Result<Self, Self::Error> {
        match val {
            0 => Ok(Self::Unknown),
            1 => Ok(Self::Uart0),
            2 => Ok(Self::Uart1),
            3 => Ok(Self::Uart2),
            4 => Ok(Self::Uart3),
            5 => Ok(Self::Gpio),
            6 => Ok(Self::SpiDevice),
            7 => Ok(Self::I2c0),
            8 => Ok(Self::I2c1),
            9 => Ok(Self::I2c2),
            10 => Ok(Self::Pattgen),
            11 => Ok(Self::RvTimer),
            12 => Ok(Self::OtpCtrl),
            13 => Ok(Self::AlertHandler),
            14 => Ok(Self::SpiHost0),
            15 => Ok(Self::SpiHost1),
            16 => Ok(Self::Usbdev),
            17 => Ok(Self::PwrmgrAon),
            18 => Ok(Self::SysrstCtrlAon),
            19 => Ok(Self::AdcCtrlAon),
            20 => Ok(Self::AonTimerAon),
            21 => Ok(Self::SensorCtrlAon),
            22 => Ok(Self::FlashCtrl),
            23 => Ok(Self::Hmac),
            24 => Ok(Self::Kmac),
            25 => Ok(Self::Otbn),
            26 => Ok(Self::Keymgr),
            27 => Ok(Self::Csrng),
            28 => Ok(Self::EntropySrc),
            29 => Ok(Self::Edn0),
            30 => Ok(Self::Edn1),
            _ => Err(val),
        }
    }
}

